1390 /// Attempt to fold a cttz/ctlz followed by a icmp plus select into a single
1391 /// call to cttz/ctlz with flag 'is_zero_poison' cleared.
1392 ///
1393 /// For example, we can fold the following code sequence:
1394 /// \code
1395 ///   %0 = tail call i32 @llvm.cttz.i32(i32 %x, i1 true)
1396 ///   %1 = icmp ne i32 %x, 0
1397 ///   %2 = select i1 %1, i32 %0, i32 32
1398 /// \code
1399 ///
1400 /// into:
1401 ///   %0 = tail call i32 @llvm.cttz.i32(i32 %x, i1 false)
1402 static Value *foldSelectCttzCtlz(ICmpInst *ICI, Value *TrueVal, Value *FalseVal,
1403                                  InstCombinerImpl &IC) {
1404   ICmpInst::Predicate Pred = ICI->getPredicate();
1405   Value *CmpLHS = ICI->getOperand(0);
1406   Value *CmpRHS = ICI->getOperand(1);
1407 
1408   // Check if the select condition compares a value for equality.
1409   if (!ICI->isEquality())
1410     return nullptr;
1411 
1412   Value *SelectArg = FalseVal;
1413   Value *ValueOnZero = TrueVal;
1414   if (Pred == ICmpInst::ICMP_NE)
1415     std::swap(SelectArg, ValueOnZero);
1416 
1417   // Skip zero extend/truncate.
1418   Value *Count = nullptr;
1419   if (!match(SelectArg, m_ZExt(m_Value(Count))) &&
1420       !match(SelectArg, m_Trunc(m_Value(Count))))
1421     Count = SelectArg;
1422 
1423   // Check that 'Count' is a call to intrinsic cttz/ctlz. Also check that the
1424   // input to the cttz/ctlz is used as LHS for the compare instruction.
1425   Value *X;
1426   if (!match(Count, m_Intrinsic<Intrinsic::cttz>(m_Value(X))) &&
1427       !match(Count, m_Intrinsic<Intrinsic::ctlz>(m_Value(X))))
1428     return nullptr;
1429 
1430   // (X == 0) ? BitWidth : ctz(X)
1431   // (X == -1) ? BitWidth : ctz(~X)
1432   // (X == Y) ? BitWidth : ctz(X ^ Y)
1433   if ((X != CmpLHS || !match(CmpRHS, m_Zero())) &&
1434       (!match(X, m_Not(m_Specific(CmpLHS))) || !match(CmpRHS, m_AllOnes())) &&
1435       !match(X, m_c_Xor(m_Specific(CmpLHS), m_Specific(CmpRHS))))
1436     return nullptr;
1437 
1438   IntrinsicInst *II = cast<IntrinsicInst>(Count);
1439 
1440   // Check if the value propagated on zero is a constant number equal to the
1441   // sizeof in bits of 'Count'.
1442   unsigned SizeOfInBits = Count->getType()->getScalarSizeInBits();
1443   if (match(ValueOnZero, m_SpecificInt(SizeOfInBits))) {
1444     // A range annotation on the intrinsic may no longer be valid.
1445     II->dropPoisonGeneratingAnnotations();
1446     IC.addToWorklist(II);
1447     return SelectArg;
1448   }
1449 
1450   // The ValueOnZero is not the bitwidth. But if the cttz/ctlz (and optional
1451   // zext/trunc) have one use (ending at the select), the cttz/ctlz result will
1452   // not be used if the input is zero. Relax to 'zero is poison' for that case.
1453   if (II->hasOneUse() && SelectArg->hasOneUse() &&
1454       !match(II->getArgOperand(1), m_One())) {
1455     II->setArgOperand(1, ConstantInt::getTrue(II->getContext()));
1456     // noundef attribute on the intrinsic may no longer be valid.
1457     II->dropUBImplyingAttrsAndMetadata();
1458     IC.addToWorklist(II);
1459   }
1460 
1461   return nullptr;
1462 }
