1290   if (match(FI, m_Sub(m_Specific(A), m_Specific(B)))) {
1291     std::swap(FI, TI);
1292     Pred = ICmpInst::getSwappedPredicate(Pred);
1293   }
1294 
1295   // With any pair of no-wrap subtracts:
1296   // (A > B) ? (A - B) : (B - A) --> abs(A - B)
1297   if (Pred == CmpInst::ICMP_SGT &&
1298       match(TI, m_Sub(m_Specific(A), m_Specific(B))) &&
1299       match(FI, m_Sub(m_Specific(B), m_Specific(A))) &&
1300       (TI->hasNoSignedWrap() || TI->hasNoUnsignedWrap()) &&
1301       (FI->hasNoSignedWrap() || FI->hasNoUnsignedWrap())) {
1302     // The remaining subtract is not "nuw" any more.
1303     // If there's one use of the subtract (no other use than the use we are
1304     // about to replace), then we know that the sub is "nsw" in this context
1305     // even if it was only "nuw" before. If there's another use, then we can't
1306     // add "nsw" to the existing instruction because it may not be safe in the
1307     // other user's context.
1308     TI->setHasNoUnsignedWrap(false);
