1324       match(FI, m_NSWSub(m_Specific(A), m_Specific(B))) &&
1325       match(TI, m_Neg(m_Specific(FI)))) {
1326     return Builder.CreateBinaryIntrinsic(Intrinsic::abs, FI,
1327                                          Builder.getFalse());
